# In-memory rate limiting (use DynamoDB/ElastiCache for production)
request_counts = {}

def validate_origin(origin: str) -> bool:
    """Validate origin against whitelist"""
    if not ALLOWED_ORIGINS or ALLOWED_ORIGINS == ['']:
        return False
    
    for allowed in ALLOWED_ORIGINS:
        allowed = allowed.strip()
        if allowed == '*':
            continue  # Never allow wildcard in production
        if origin == allowed:
            return True
        # Support wildcard subdomains
        if allowed.startswith('*.'):
            domain = allowed[2:]
            if origin.endswith(domain):
                return True
    return False

def get_cors_headers(origin: str = None) -> Dict[str, str]:
    """Generate secure CORS headers with origin validation"""
    headers = {
        'Content-Type': 'application/json',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'X-XSS-Protection': '1; mode=block',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        'Cache-Control': 'no-store, no-cache, must-revalidate, private',
        'Pragma': 'no-cache'
    }
    
    # Validate and set CORS headers
    if origin and validate_origin(origin):
        headers['Access-Control-Allow-Origin'] = origin
        headers['Access-Control-Allow-Credentials'] = 'true'
    else:
        # For development only - remove in production
        if os.environ.get('ENVIRONMENT') == 'development':
            headers['Access-Control-Allow-Origin'] = origin or '*'
    
    headers['Access-Control-Allow-Methods'] = 'GET, POST, OPTIONS'
    headers['Access-Control-Allow-Headers'] = f'Content-Type, Authorization, {API_KEY_HEADER}, X-Request-ID'
    headers['Access-Control-Max-Age'] = '3600'
    
    return headers

def verify_api_key(api_key: str) -> bool:
    """Verify API key using HMAC"""
    if not HMAC_SECRET or not api_key:
        return False
    
    try:
        parts = api_key.split('.')
        if len(parts) != 2:
            return False
        
        payload, signature = parts
        expected_signature = hmac.new(
            HMAC_SECRET.encode(),
            payload.encode(),
            hashlib.sha256
        ).hexdigest()
        
        return hmac.compare_digest(signature, expected_signature)
    except Exception:
        return False

def check_rate_limit(identifier: str) -> bool:
    """Simple rate limiting check"""
    current_time = int(time.time())
    window_start = current_time - RATE_LIMIT_WINDOW
    
    # Clean old entries
    expired_keys = [k for k, v in request_counts.items() if v['timestamp'] < window_start]
    for key in expired_keys:
        del request_counts[key]
    
    if identifier not in request_counts:
        request_counts[identifier] = {'count': 1, 'timestamp': current_time}
        return True
    
    if request_counts[identifier]['timestamp'] < window_start:
        request_counts[identifier] = {'count': 1, 'timestamp': current_time}
        return True
    
    if request_counts[identifier]['count'] >= RATE_LIMIT_MAX_REQUESTS:
        return False
    
    request_counts[identifier]['count'] += 1
    return True

def sanitize_input(data: Any) -> Any:
    """Sanitize input data to prevent injection attacks"""
    if isinstance(data, dict):
        return {k: sanitize_input(v) for k, v in data.items()}
    elif isinstance(data, list):
        return [sanitize_input(item) for item in data]
    elif isinstance(data, str):
        # Remove potential script tags and SQL injection patterns
        dangerous_patterns = ['<script', 'javascript:', 'onerror=', 'onload=', '--', ';--', '/*', '*/', 'xp_', 'sp_']
        sanitized = data
        for pattern in dangerous_patterns:
            sanitized = sanitized.replace(pattern, '')
        return sanitized[:1000]  # Limit string length
    return data

